**1. Board Class**

```python
"""
This class represents the checkers board and manages its state.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Place pieces on the board
        piece_types = ['R', 'B']
        for i, row in enumerate(range(3, -1, -1)):
            for j, col in enumerate(range(0, 8, 2)):
                self.board[row][col] = Piece(piece_types[i], (row, col))
                if row > 4:
                    break
        for i, row in enumerate(range(5, 8)):
            for j, col in enumerate(range(1, 9, 2)):
                self.board[row][col] = Piece(piece_types[1 - i], (row, col))

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if piece:
            self.board[from_pos[0]][from_pos[1]] = None
            self.board[to_pos[0]][to_pos[1]] = piece
            piece.move(to_pos)

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece) if piece else "." for piece in row]))
```

**2. Piece Class**

```python
"""
This class represents a checkers piece.
"""

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.kinged = False

    def move(self, new_position):
        self.position = new_position

    def king(self):
        self.kinged = True

    def __str__(self):
        if self.kinged:
            return f"{self.color}K"
        else:
            return self.color
```

**3. Game Class**

```python
"""
This class manages the game logic.
"""

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'R'

    def switch_turn(self):
        self.current_player = 'B' if self.current_player == 'R' else 'R'

    def print_board(self):
        self.board.print_board()

    def make_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos)
        if piece and piece.color == self.current_player:
            self.board.move_piece(from_pos, to_pos)
            # Handle kinging
            if piece.color == 'R' and to_pos[0] == 7 or piece.color == 'B' and to_pos[0] == 0:
                piece.king()
            self.switch_turn()

    def check_winner(self):
        # Check for winning condition (no more pieces of one color left)
        red_pieces = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'R')
        black_pieces = sum(1 for row in self.board.board for piece in row if piece and piece.color == 'B')
        if red_pieces == 0:
            return 'B wins'
        elif black_pieces == 0:
            return 'R wins'
        else:
            return None
```

