"""
This class contains utility functions.
"""

import re

def is_valid_move(board, from_pos, to_pos):
    piece = board.get_piece(from_pos)
    if not piece or piece.color != board.current_player:
        return False
    # Add more move validation logic here (e.g., capture, legal moves)
    return True

def parse_move(move_str):
    if len(move_str) != 4 or not re.match(r'^[a-h][1-8]-[a-h][1-8]$', move_str):
        raise ValueError("Invalid move format")
    from_pos = (int(move_str[3]) - 1, ord(move_str[0]) - 97)
    to_pos = (int(move_str[1]) - 1, ord(move_str[2]) - 97)
    return from_pos, to_pos
```

**5. Main Module**

