"""
This is the main module to launch the program.
"""

from game import Game

def run():
    game = Game()
    while True:
        game.print_board()
        move_str = input(f"{game.current_player}'s turn (format: from-to): ")
        try:
            from_pos, to_pos = parse_move(move_str)
            if is_valid_move(game.board, from_pos, to_pos):
                game.make_move(from_pos, to_pos)
                winner = game.check_winner()
                if winner:
                    print(winner)
                    break
            else:
                print("Invalid move. Please try again.")
        except ValueError as e:
            print(e)

if __name__ == "__main__":
    run()
